import{_ as p,o as e,c as t,ag as r}from"./chunks/framework.ETe_P6d1.js";const u=JSON.parse('{"title":"一、研究背景与问题提出","description":"","frontmatter":{},"headers":[],"relativePath":"reports/马尔彦/马尔彦_马尔彦-关于近代侨乡建筑的文化转译与技术在地融合的调研报告.md","filePath":"reports/马尔彦/马尔彦_马尔彦-关于近代侨乡建筑的文化转译与技术在地融合的调研报告.md"}'),o={name:"reports/马尔彦/马尔彦_马尔彦-关于近代侨乡建筑的文化转译与技术在地融合的调研报告.md"};function _(i,a,l,s,h,n){return e(),t("div",null,[...a[0]||(a[0]=[r('<h3 id="近代侨乡建筑的文化转译与技术在地融合——基于开平立园碉楼群与仓东村聚落的实地考察" tabindex="-1">近代侨乡建筑的文化转译与技术在地融合——基于开平立园碉楼群与仓东村聚落的实地考察 <a class="header-anchor" href="#近代侨乡建筑的文化转译与技术在地融合——基于开平立园碉楼群与仓东村聚落的实地考察" aria-label="Permalink to &quot;近代侨乡建筑的文化转译与技术在地融合——基于开平立园碉楼群与仓东村聚落的实地考察&quot;">​</a></h3><p>考察地点： 广东省江门市开平市</p><p>学生姓名：马尔彦<br> 考察时间： 2026年3月31日<br> 指导教师： 石拓、王琛</p><h1 id="一、研究背景与问题提出" tabindex="-1">一、研究背景与问题提出 <a class="header-anchor" href="#一、研究背景与问题提出" aria-label="Permalink to &quot;一、研究背景与问题提出&quot;">​</a></h1><p>本研究聚焦开平地区两类典型遗产实践：由华侨实业家谢维立于1926-1936年建造的立园，呈现精英阶层主导的中西符号系统性整合；以及2015年启动的仓东村聚落再生项目，彰显社区参与下的本土材料技术转译。二者构成观察侨乡应对全球化冲击的辩证样本。核心问题在于：当立园以巴洛克穹顶（如牌楼顶部仿圣彼得大教堂设计）与中式灰塑（&quot;百鸟朝凤&quot;主题）拼贴彰显身份时，仓东村民选择用掺入蚝壳的夯土修补祖屋。两种策略背后折射出何种文化认同哲学与技术在地性融合？</p><h1 id="二、立园-中西元素结合中体现的文化身份困境" tabindex="-1">二、立园：中西元素结合中体现的文化身份困境 <a class="header-anchor" href="#二、立园-中西元素结合中体现的文化身份困境" aria-label="Permalink to &quot;二、立园：中西元素结合中体现的文化身份困境&quot;">​</a></h1><p>立园泮立楼为园主谢维立与四位太太的居所，其内部装饰别具一格，融合了中西文化元素，营造出独特的艺术氛围。</p><p>图 1：立园泮立楼(./images/1.jpg)</p><p>步入泮立楼，抬头便能望见那西式风格的天花板装饰。几何形状的线条勾勒出规整的图案，色彩搭配和谐雅致，仿若将西方建筑的典雅与精致浓缩于一方天地。在灯光的映照下，天花板熠熠生辉，散发着古典的浪漫气息。楼内的仿罗马柱矗立其间，气势恢宏。柱身雕刻精美，细腻的纹理仿佛诉说着古罗马建筑的辉煌历史。它们不仅是建筑结构上的支撑，更是艺术美感的彰显，为整座楼增添了庄重与威严。而中式壁画则是泮立楼内一抹亮丽的东方色彩。壁画上，或描绘着历史典故，人物栩栩如生，仿佛能让人穿越时空，感受古人的风采；或展现着山水田园的诗意画卷，青山绿水、花鸟虫鱼，尽显自然之美。中式壁画与西式天花板、仿罗马柱以及国外地砖相得益彰，中西合璧，共同绘就了泮立楼内美轮美奂的景致，让人不禁沉醉于这独特的艺术魅力之中。</p><p>图 2：泮立楼中西式天花板和中式壁画(./images/2.jpg)</p><p>图 3：泮立楼中仿罗马柱头(./images/3.jpg)</p><p>同时，我注意到立园各建筑内使用了从国外带回的各式地砖，同时有壁炉设计，但由于当地限制并未投入使用，体现出园主身上在国外生活的痕迹；屋内家具又大量采用中式家具，体现出园主对故乡的归属感。</p><p>图 4：西方地砖与中式家具(./images/4.jpg)</p><p>图 5：壁炉(./images/5.jpg)</p><p>我隐隐感到，立园的建造映射出早期全球化下华侨群体的认同焦虑。谢维立通过采购西方建筑符号构建&quot;高等华人&quot;形象，这种符号移植存在本质断裂——花园中高达4.2米的“打虎鞭”雕塑，原为客家勇武象征，在玫瑰园中沦为景观道具，揭示其物质丰饶与精神漂泊的悖论。</p><p>图 6：“打虎鞭”雕塑(./images/6.jpg)</p><p>立园的建筑技术层面虽有创新（如青砖墙体嵌入钢筋混凝土过梁提升抗震性），但中西元素的拼凑导致建构逻辑消解：仿科林斯柱仅作为立面装饰，实际承重由内侧砖墙承担；进口水磨石地面图案复制凡尔赛宫纹样，却无对应空间仪式。这些现象表明，立园的华丽拼贴实为脱离土地伦理的文化装置，其完美表象下隐隐显现的认同危机。</p><h1 id="三、仓东村-材料劳作中的社群记忆再生" tabindex="-1">三、仓东村：材料劳作中的社群记忆再生 <a class="header-anchor" href="#三、仓东村-材料劳作中的社群记忆再生" aria-label="Permalink to &quot;三、仓东村：材料劳作中的社群记忆再生&quot;">​</a></h1><p>仓东村实践证明文化延续根植于材料的地方性&quot;劳作&quot;。村民采用传统蚝壳灰夯土工艺（掺入稻壳增强抗裂性），在共同夯实墙体过程中，阿婆黄月娇的手印与青年工具痕被永久封存于墙面，使夯土成为社群记忆的承载。屋面改造回收70%旧陶瓦，新瓦仅用于30%损毁区域，使每片瓦都携带历史叙事，尽可能保留了其历史传承。</p><p>仓东村以秉文谢公祠与侯成谢公祠为核心的文化遗产教育基地（“仓东计划”），代表了一种社区驱动的整体性保护范式。两座公祠均建于1934年，采用岭南传统祠堂形制（三进院落布局），同时融入西式拱窗、混凝土圆柱与巴洛克山花装饰，其建筑语汇映射了近代华侨“以西方技术表达宗族伦理”的文化协商逻辑。内部空间保存的灰雕壁画（如《郭子仪庆寿》）、楹联（如“东山相业；北府军威”）及《时局图》等文物，揭示华侨群体对家国命运的关注。2011年启动的修复工程坚持“可逆性原则”：利用原址青砖修补墙体裂缝，复原木雕神龛（保留70%原件），并将西侧厢房改造为华侨移民史展厅，使建筑同时承担宗族祭祀与公共教育功能。通过修复技术、社区协作、矛盾调解、可持续挑战的逻辑链条，呈现活态遗产保护的复杂性。</p><p>图 7：仓东村侯成谢公祠(./images/7.jpg)</p><p>图 8：西式拱窗、混凝土圆柱(./images/8.jpg)</p><p>我还注意到，仓东村中有许多碉楼，由村民众筹合资建造，其资金集中于防御功能（64个射击孔、铁门防弹层），装饰仅保留灰塑蝙蝠纹（“福”）与枪眼边框线脚，单座造价仅为立园碉楼的1/20。为应对匪患，合资建楼是平民的生存策略，体现村民“风险共担、资源共享”原则。</p><p>图 9：仓东村碉楼1(./images/9.jpg)</p><p>图 10：仓东村碉楼2(./images/10.jpg)</p><p>仓东朴素碉楼的斑驳夯土墙，既无彩釉玻璃亦无水磨石柱，却承载着村民的银元契约与铜铃警报绳，成为比任何华丽装饰更深刻的“地方性印记”。它提示我们：遗产保护的目光，应从符号奇观投向那些沉默的生存智慧。</p><h1 id="四、批判性对比-视觉正确性与劳作真实性的冲突" tabindex="-1">四、批判性对比：视觉正确性与劳作真实性的冲突 <a class="header-anchor" href="#四、批判性对比-视觉正确性与劳作真实性的冲突" aria-label="Permalink to &quot;四、批判性对比：视觉正确性与劳作真实性的冲突&quot;">​</a></h1><p>立园与仓东村的差异直指遗产保护的核心矛盾。立园范式依赖符号拼凑，其罗马柱装饰与水道桥通过视觉奇观构建身份认同，却因脱离地域文脉成为静态标本。与之相对，仓东范式遵循材料伦理原则：稻壳夯土墙（材料成本仅为仿古砖墙1/3）因承载村民劳作记忆获得生命力；旧瓦回收体系不仅降低资源消耗，更使匠人知识在青年分拣瓦片时传递。</p><p>二者根本分歧在于，立园将地方性等同于符号的视觉正确性，仓东则锚定于材料与劳作的共生关系。前者如毓培别墅彩窗《二十四孝》图，用西方技术承载儒家训导，因缺乏日常实践支撑沦为文化悬浮；后者如夯土墙冬暖夏凉特性，在物理性能与情感价值统一中实现了真实存续。</p><h1 id="五、保护策略的重构路径" tabindex="-1">五、保护策略的重构路径 <a class="header-anchor" href="#五、保护策略的重构路径" aria-label="Permalink to &quot;五、保护策略的重构路径&quot;">​</a></h1><p>基于批判认知，我提出以下实践转向：</p><ol><li>解构符号神话，重释立园价值<br> 跳出“形式拼贴”批判，将其视为早期全球化文化协商的档案；在解说系统中强化历史语境阐释，避免符号的扁平化解读，如&quot;打虎鞭&quot;在传统客家语境象征男性气概，置于玫瑰园后蜕变为装饰物。可以将其定位为全球本土化早期实验的失败案例，而非审美典范。</li><li>制定材料伦理宪章，推广仓东智慧<br> 编制乡土再生技术相关文献，要求项目披露材料碳足迹（如稻壳夯土减少水泥用量）与社群参与度。推动案例进入建筑教育，彰显文化生产力，建立“社区-学界-政府”三方协作的遗产治理框架。</li><li>建立&quot;关系存续度&quot;评估新标准<br> 替代&quot;形式完整度&quot;旧指标，重点考察：材料是否延续地方智慧（如夯土掺稻壳抗裂工艺）、空间是否激活协作网络（如祠堂改造的村民议事厅使用频次）、技术是否承载演进叙事（如可拆卸光伏支架预留传统瓦复兴接口）等。</li></ol><p>当立园的混凝土穹顶因维护成本过高日渐斑驳，仓东的夯土墙却在雨季后的补夯中愈显浑厚。这昭示着遗产活化的本质：真正的生命不在符号的完美陈列，而在材料与人的劳作持续对话中生长的韧性。总之，当代遗产保护需在符号意义阐释与材料技术传承间建立对话，使历史建筑成为文化连续性的载体而非断裂的标本。</p><h1 id="六、附录-调研记录" tabindex="-1">六、附录：调研记录 <a class="header-anchor" href="#六、附录-调研记录" aria-label="Permalink to &quot;六、附录：调研记录&quot;">​</a></h1><p>6.1 摄影记录</p><p>本报告共插入10张现场照片，分别展示：</p><p>图1-图5：立园建筑外观与内部装饰</p><p>图6：立园中“打虎鞭”雕塑</p><p>图7-图8：仓东村侯成谢公祠</p><p>图9-图10：仓东村碉楼</p><p>6.2 文献资料</p><p>参考书目：</p><p>《华侨建筑文化研究》，华侨大学建筑学院，中国建筑工业出版社，2010</p><p>《文化遗产保护的理论与实践》，同济大学建筑与城市规划学院，同济大学出版社，2015</p><p>《开平碉楼村落保护与利用研究》，华南理工大学出版社，2018</p><p>报告撰写人：马尔彦<br> 报告完成时间： 2026年4月19日<br> 字数统计： 约3100字</p>',46)])])}const c=p(o,[["render",_]]);export{u as __pageData,c as default};
